// Transform with map
const numbers = [1, 2, 3, 4, 5];
const doubled = _.map(numbers, n => n * 2);

// Filter elements
const evens = _.filter(numbers, n => n % 2 === 0);

// Find first match
const users = [{ name: 'John', active: false }, { name: 'Jane', active: true }];
const firstActive = _.find(users, {active: true});

// Reduce to single value
const sum = _.reduce(numbers, (acc, n) => acc + n, 0);

output = { doubled, evens, firstActive, sum };
`;case"lodash_array_manipulation":return`// Array Manipulation Functions
const array = [1, 2, 3, 4, 5, 6, 7, 8];

// Concatenate arrays
const concatenated = _.concat([1, 2], [3, 4], [5, 6]);
// Result: [1, 2, 3, 4, 5, 6]

// Find differences between arrays
const diff = _.difference([1, 2, 3, 4, 5], [3, 4]);
// Result: [1, 2, 5]

// Find intersection of arrays
const intersection = _.intersection([1, 2, 3], [2, 3, 4]);
// Result: [2, 3]

// Union of arrays (combines and removes duplicates)
const union = _.union([1, 2], [2, 3], [3, 4]);
// Result: [1, 2, 3, 4]

// Pull specific values from array
const pulled = _.pull([1, 2, 3, 4, 5], 2, 4);
// Result: [1, 3, 5] (modifies original array)

output = { concatenated, diff, intersection, union, pulled };
`;case"lodash_array_flattening":return`// Array Flattening Functions
// Flatten one level
const nested = [1, [2, 3], [4, [5, 6]]];
const flattened = _.flatten(nested);
// Result: [1, 2, 3, 4, [5, 6]]

// Flatten recursively (deep)
const deepNested = [1, [2, [3, [4]], 5]];
const deepFlattened = _.flattenDeep(deepNested);
// Result: [1, 2, 3, 4, 5]

// Zip arrays together
const names = ['John', 'Jane', 'Bob'];
const ages = [30, 25, 35];
const zipped = _.zip(names, ages);
// Result: [['John', 30], ['Jane', 25], ['Bob', 35]]

// Unzip arrays
const unzipped = _.unzip(zipped);
// Result: [['John', 'Jane', 'Bob'], [30, 25, 35]]

output = { nested, flattened, deepFlattened, zipped, unzipped };
`;case"lodash_array_aggregation":return`// Array Aggregation Functions
const numbers = [1, 2, 3, 4, 5];
const scores = [85, 92, 78, 96, 88];

// Sum values
const total = _.sum(numbers);
// Result: 15

// Find max/min
const maximum = _.max(scores);
const minimum = _.min(scores);
// Result: 96, 78

// Calculate average
const average = _.mean(scores);
// Result: 87.8

// Sum by property
const products = [{ price: 10 }, { price: 20 }, { price: 15 }];
const totalPrice = _.sumBy(products, 'price');
// Result: 45

// Average by property
const avgPrice = _.meanBy(products, 'price');
// Result: 15

output = { total, maximum, minimum, average, totalPrice, avgPrice };
`;case"lodash_array_organization":return`// Array Organization Functions
const users = [
  { name: 'John', age: 30, department: 'IT' },
  { name: 'Jane', age: 25, department: 'HR' },
  { name: 'Bob', age: 35, department: 'IT' }
];

// Sort by property
const sortedByAge = _.sortBy(users, 'age');
// Result: [Jane(25), John(30), Bob(35)]

// Sort by multiple properties
const sortedMultiple = _.sortBy(users, ['department', 'age']);
// Result: sorted by department first, then age

// Order by with direction
const orderedDesc = _.orderBy(users, ['age'], ['desc']);
// Result: [Bob(35), John(30), Jane(25)]

// Shuffle array randomly
const numbers = [1, 2, 3, 4, 5];
const shuffled = _.shuffle(numbers);
// Result: randomly ordered array

// Reverse array
const reversed = _.reverse([...numbers]);
// Result: [5, 4, 3, 2, 1]

output = { sortedByAge, sortedMultiple, orderedDesc, shuffled, reversed };
